#![allow(dead_code)]

use beads_core::{EventBody, encode_event_body_canonical, sha256_bytes};

use super::event_body;

pub const GOLDEN_EVENT_BODY_CBOR_HEX: &str = "";
pub const GOLDEN_EVENT_BODY_SHA256_HEX: &str =
    "450523152c01d1700a790c7b27a3a71810d3474aa176a16ad779abc7437d9614";

pub fn golden_event_body() -> EventBody {
    event_body::sample_event_body(1)
}

pub fn golden_event_body_cbor() -> Vec<u8> {
    decode_hex(GOLDEN_EVENT_BODY_CBOR_HEX)
}

pub fn golden_event_body_bytes() -> Vec<u8> {
    encode_event_body_canonical(&golden_event_body())
        .expect("fixture event encodes")
        .as_bytes()
        .to_vec()
}

pub fn sha256_hex(bytes: &[u8]) -> String {
    sha256_bytes(bytes)
        .as_bytes()
        .iter()
        .map(|b| format!("{:02x}", b))
        .collect()
}

pub fn fingerprint_bytes(bytes: &[u8]) -> String {
    format!("sha256:{} bytes:{}", sha256_hex(bytes), bytes.len())
}

fn decode_hex(hex: &str) -> Vec<u8> {
    assert_eq!(hex.len() % 2, 0, "fixture hex must have even length");

    hex.as_bytes()
        .chunks_exact(2)
        .map(|pair| {
            let hi = hex_nibble(pair[0]).expect("fixture hex must be valid");
            let lo = hex_nibble(pair[1]).expect("fixture hex must be valid");
            (hi << 4) | lo
        })
        .collect()
}

fn hex_nibble(byte: u8) -> Option<u8> {
    match byte {
        b'0'..=b'9' => Some(byte - b'0'),
        b'a'..=b'f' => Some(byte - b'a' + 10),
        b'A'..=b'F' => Some(byte - b'A' + 10),
        _ => None,
    }
}
